validation.test_code:
void test_thread_func_returns_null(void) {
    void *result = thread_func(NULL);
    TEST_ASSERT_NULL(result);
}

void test_create_and_join_success(void) {
    pthread_t tid;
    int rc = pthread_create(&tid, NULL, thread_func, NULL);
    TEST_ASSERT_EQUAL_INT(0, rc);
    int join_rc = pthread_join(tid, NULL);
    TEST_ASSERT_EQUAL_INT(0, join_rc);
}

void test_join_after_create(void) {
    pthread_t tid;
    if (pthread_create(&tid, NULL, thread_func, NULL) == 0) {
        int result = pthread_join(tid, NULL);
        TEST_ASSERT_EQUAL_INT(0, result);
    }
}

int main(void) {
    RUN_TEST(test_thread_func_returns_null);
    RUN_TEST(test_create_and_join_success);
    RUN_TEST(test_join_after_create);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

